for(let i=108;i<=109;i++) if(!D.find(d=>d.d===i)) D.push({ph:'p6',d:i,t:'LinkedIn & Applications',tp:'Optimise LinkedIn, start applying',why:'<strong>5 quality applications per week.</strong> Start now.',res:[{t:'Naukri DE jobs',u:'https://www.naukri.com/data-engineer-jobs'}],q:'How many targeted applications per week?',o:['1-2','5-10 quality — track in a spreadsheet'],c:1,ex:'Quality > quantity, but 5/week keeps your pipeline full.',xp:25});
